final:
module ShiftReg_16_load(
   input                clk,
   input                rst,
   input                load,
   input  [15:0]        load_val,
   output reg [15:0]    obf_Q
);
    always@(posedge clk)begin
        if(rst) obf_Q <= 16'd0;
        else if(load) obf_Q <= load_val;
        else obf_Q <= {obf_Q[14:0], 1'b0};
    end
endmodule
